const input = $input.first()?.json || {};
return [{ json: {
  run_date: input.run_date || new Date().toISOString().slice(0,10),
  mode: input.mode || 'daily',
  facility_code: input.facility_code || 'CIGLI_HOSP',
  facility_name: input.facility_name || 'Demo Hospital Çiğli Hastanesi',
  metric_profile: input.metric_profile || 'hospital_standard',
  tags: input.tags || []
}}];

const fs = require('fs');
const raw = fs.readFileSync('/docs/metric_profiles.json', 'utf8');
const profiles = JSON.parse(raw).profiles || {};
const item = $input.first().json;
const profile = profiles[item.metric_profile];
if (!profile) {
  throw new Error(`Metric profile not found: ${item.metric_profile}`);
}
return [{ json: { ...item, profile } }];

